// Schedule.js
import React from "react";
import "../admin/Admin.css";

export default function StudentSchedule() {
  return (
    <div className="admin-page fade-in">
      <div className="page-header"><h1>Lịch học</h1><p>Lịch học và các buổi học sắp tới</p></div>
      <div className="section-card">
        <div className="empty-state"><p>📅 Chưa có lịch học nào được sắp xếp</p></div>
      </div>
    </div>
  );
}
